// Avatar catalog for profile selection.
//
// Was 10 named-colour crayon circles → then 12 species tiles that
// overlapped with the Character Builder picker. Rewritten 2026-05
// as a fresh mix of magical creatures + friendly objects so the
// avatar picker feels distinct from "pick a species for your story"
// and gives the kid more identity options (the dragon kid, the
// rainbow kid, the rocket kid). All face-only chibi heads on
// transparent backgrounds, generated by
// scripts/generate-profile-avatars.ts via gpt-image-2 high then
// bg-stripped via Replicate (851-labs/background-remover).
//
// Each entry carries a soft tinted background — different per
// avatar so 12 round avatars don't all look like the same orange
// ball.

export type Avatar = {
  id: string;
  /** Display label (used as aria-label + the initials fallback). */
  name: string;
  /**
   * R2 key for the illustrated tile. Resolved at render time by
   * `resolveThumbnailUrl` against `NEXT_PUBLIC_R2_PUBLIC_URL`.
   */
  imageKey: string;
  /**
   * Tailwind bg class for the tinted circle behind the illustration.
   * Soft tints so the colour reads without competing with the art.
   * Mirrors the per-item colour variety on the Character Builder
   * species tiles.
   */
  bg: string;
};

