// Default avatar for new profiles. `crayon` is the brand-friendly
// no-bias starter (was previously `bunny` from the species set).
export const DEFAULT_AVATAR_ID = 'ice-cream';

// Legacy ID map — every old `crayon-*` ID resolves to a sensible new
// tile so existing profiles in the DB keep rendering after the
// catalog rewrite. No DB migration needed; the resolver
// transparently swaps them. Removing this map is safe once every
// active profile has been re-saved with a new ID (i.e. every parent
// has hit "edit profile" at least once).
const LEGACY_AVATAR_MAP: Record<string, string> = {
  // Original crayon-colour IDs (pre-2026 illustrated avatars).
  'crayon-red': 'dragon',
  'crayon-orange': 'ice-cream',
  'crayon-yellow': 'sun',
  'crayon-green': 'alien',
  'crayon-blue': 'rocket',
  'crayon-purple': 'unicorn',
  'crayon-pink': 'superhero',
  'crayon-brown': 'wizard',
  'crayon-teal': 'mermaid',
  'crayon-coral': 'astronaut',
  // First illustrated set (animals — 2026-05, replaced same month).
  // Map each old species to the most-similar magical / object so
  // existing profiles don't grey-chip after the migration.
  cat: 'ice-cream',
  dog: 'ice-cream',
  bunny: 'fairy',
  fox: 'dragon',
  lion: 'sun',
  panda: 'ghost',
  frog: 'alien',
  turtle: 'mermaid',
  owl: 'wizard',
  // Second illustrated set (magical creatures — 2026-05, swap day).
  // fairy + monster + robot were dropped to avoid overlap with the
  // Character Builder species picker. Map to similar costume picks.
  fairy: 'wizard',
  monster: 'alien',
  robot: 'astronaut',
  // The five never-filled placeholder slots fall through to defaults
  // — anyone with one of these in the DB is a pre-launch test row.
  'avatar-01': 'ice-cream',
  'avatar-02': 'rainbow',
  'avatar-03': 'unicorn',
  'avatar-04': 'dragon',
  'avatar-05': 'astronaut',
  // Schema default — `avatarId String @default("default")` lives on
  // every profile that was created before the picker was wired up
  // (most "Artist" / "Artist (imported)" rows are in this bucket).
  // Without this mapping they render as grey initials chips.
  default: DEFAULT_AVATAR_ID,
};

const resolveLegacy = (avatarId: string): string =>
  LEGACY_AVATAR_MAP[avatarId] ?? avatarId;

// Get avatar by ID. Transparently maps legacy IDs (e.g. `crayon-orange`)
// to their replacement in the new catalog so existing profiles don't
// render as broken.
export const getAvatar = (avatarId: string): Avatar | undefined => {
  const id = resolveLegacy(avatarId);
  return AVATARS.find((avatar) => avatar.id === id);
};

// Every avatar in the new catalog is selectable — no placeholder
// shape any more. Kept as a function so consumers don't import the
// raw array (insulates them from future shape changes).
export const getSelectableAvatars = (): Avatar[] => AVATARS;

// Initials from name as the final visual fallback when the avatar
// image fails to load and we have nothing else to show.
export const getInitials = (name: string): string => {
  return name
    .split(' ')
    .map((word) => word[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);
};
